import { describe, it, expect } from "vitest";
import { processScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  describe("quote", () => {
    it.todo("quotes a single sword for a new customer (base 100 + 10% first-insurance + 5G fee)");
    it.todo("quotes each main item type (sword 1000/100, amulet 600/60, staff 800/80, potion 400/40)");
    it.todo("quotes 3 alike components as a special block (60G base premium instead of 75G)");
    it.todo("adds 50% surcharge for a cursed item");
    it.todo("adds 30% surcharge for a highly enchanted item (enchantment >= 5)");
    it.todo("applies 20% loyalty discount for customers with >= 2 years");
    it.todo("applies 15% discount on contracts after the first");
    it.todo("rounds the final premium up (in MHPCO's favor)");
  });

  describe("claim", () => {
    it.todo("reimburses damage minus 100G deductible for a normal item");
    it.todo("reimburses 50% of damage for items with enchantment >= 8");
    it.todo("reimburses 100% of damage for items made of dragon material");
    it.todo("caps total payout per policy at twice the insurance sum");
  });
});

