type Item = {
  type: string;
  material: string;
  enchantment: number;
  cursed: boolean;
};

type QuoteStep = { op: "quote"; items: Item[] };

type Scenario = {
  customer: { yearsWithMHPCO: number };
  steps: QuoteStep[];
};

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

export const processScenario = (scenario: Scenario): { results: unknown[] } => {
  const results = scenario.steps.map((step) => {
    const base = step.items.reduce(
      (sum, item) => sum + (BASE_PREMIUM[item.type] ?? 0),
      0,
    );
    const premium = Math.ceil(base * 1.1) + 5;
    return { premium };
  });
  return { results };
};

