const MAIN_BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

const COMPONENT_BASE_PREMIUM = 25;
const COMPONENT_BLOCK_PREMIUM = 60;

const basePremiumForItems = (items: Item[]): number => {
  let base = 0;
  const componentCounts: Record<string, number> = {};
